import { mapState } from "vuex";
export default {
  props: {
    champion: Object
  },
  methods: {
    getChampionImgUrl(champion) {
      const {
        host,
        port
      } = this.$store.state.config.download;
      return `${host}:${port}/champions/${champion.id}.jpg`;
    }
  },
  computed: mapState({
    selectedChampion: state => state.collection.selectedChampion
  })
};
